 30→const getPercentageStyle = (percentage: number): React.CSSProperties => {
 31→	const adjustedPercentage = Math.max(0, percentage - 5);
 32→	const intensity = Math.min(adjustedPercentage / 25, 1);
 33→	const red = Math.round(245 + (248 - 245) * intensity);
 34→	const green = Math.round(245 * (1 - intensity));
