  4→import { Button } from '../../../../components/Button'
  5→import { Input } from '../../../../components/forms/Input'
  6→import { Body } from '../../../../components/typography/Body'
  7→import { type ContactDetailsFormData } from './validation'
  8→
  9→const DisclaimerText = styled(Body)(
 10→  ({ theme: { spacing } }) => css`
 11→    margin-bottom: ${spacing.m};
 12→  `
 13→)
 14→
 15→type ContactDetailsProps = {
 16→  formData: ContactDetailsFormData
 17→  setFormData: (data: Partial<ContactDetailsFormData>) => void
 18→  onNext: () => void
 19→}
 20→
 21→type FormErrors = {
 22→  [K in keyof ContactDetailsFormData]?: string
 23→}
 24→
 25→const contactFields: (keyof ContactDetailsFormData)[] = ['firstName', 'lastName', 'email', 'phone']
 26→
 27→export const ContactDetails = ({ formData, setFormData, onNext }: ContactDetailsProps) => {
 28→  const [errors, setErrors] = useState<FormErrors>({})
 29→  const [form, setForm] = useState<ContactDetailsFormData>(formData)
 30→  const [isSubmitted, setIsSubmitted] = useState(false)
 31→
 32→  const validateField = (name: keyof ContactDetailsFormData, value: string): string | undefined => {
 33→    if (!value) return 'Required'
 34→
 35→    switch (name) {
 36→      case 'firstName':
 37→      case 'lastName': {
 38→        return value.length < 2 ? 'Must be at least 2 characters' : undefined
 39→      }
 40→      case 'email': {
 41→        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
 42→          ? undefined
 43→          : 'Please enter a valid email address'
 44→      }
 45→      case 'phone': {
 46→        return value.length < 10 ? 'Please enter a valid phone number' : undefined
 47→      }
 48→      default: {
 49→        return undefined
 50→      }
 51→    }
 52→  }
 53→
 54→  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
 55→    const { name, value } = e.target
 56→    setForm((prev) => ({ ...prev, [name]: value }))
 57→
 58→    if (isSubmitted) {
 59→      const error = validateField(name as keyof ContactDetailsFormData, value)
 60→      setErrors((prev) => ({
 61→        ...prev,
 62→        [name]: error,
 63→      }))
 64→    }
 65→  }
 66→
 67→  const handleNext = () => {
 68→    setIsSubmitted(true)
 69→
 70→    // Validate only contact fields
 71→    const newErrors: FormErrors = {}
 72→    let hasErrors = false
 73→
 74→    for (const field of contactFields) {
 75→      const error = validateField(field, form[field])
 76→      if (error) {
 77→        newErrors[field] = error
 78→        hasErrors = true
 79→      }
 80→    }
 81→
 82→    setErrors(newErrors)
 83→
 84→    if (!hasErrors) {
 85→      setFormData(form)
 86→      onNext()
 87→    }
 88→  }
 89→
 90→  return (
 91→    <div className="form">
 92→      <Input
 93→        label="First name"
 94→        placeholder="John"
 95→        name="firstName"
 96→        value={form.firstName}
 97→        onChange={handleChange}
 98→        error={isSubmitted ? errors.firstName : undefined}
 99→      />
100→      <Input
101→        label="Last name"
102→        placeholder="Doe"
103→        name="lastName"
104→        value={form.lastName}
105→        onChange={handleChange}
106→        error={isSubmitted ? errors.lastName : undefined}
107→      />
108→      <Input
109→        label="Email"
110→        type="email"
111→        placeholder="email address"
112→        name="email"
113→        value={form.email}
114→        onChange={handleChange}
115→        error={isSubmitted ? errors.email : undefined}
116→      />
117→      <Input
118→        label="Phone number"
119→        placeholder="phone number"
120→        type="tel"
121→        name="phone"
122→        value={form.phone}
123→        onChange={handleChange}
124→        error={isSubmitted ? errors.phone : undefined}
125→      />
126→      <DisclaimerText size="XXS" type="span">
127→        We'll only use your phone to call you about your order
128→      </DisclaimerText>
129→      <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
130→        <Button onClick={handleNext}>Next</Button>
131→      </div>
132→    </div>
133→  )
134→}
135→

