import preview from '#.storybook/preview'
import { expect } from 'storybook/test'

import { CheckoutPage } from './CheckoutPage'

const meta = preview.meta({
  component: CheckoutPage,
  tags: ['ai-generated'],
  parameters: {
    layout: 'fullscreen',
  },
})

export const Default = meta.story({
  play: async ({ canvas }) => {
    await expect(canvas.getByText('Checkout')).toBeVisible()
    await expect(canvas.getByText('Your cart is empty.')).toBeVisible()
  },
})

export const FilledForm = meta.story({
  play: async ({ canvas, userEvent }) => {
    await expect(canvas.getByText('Checkout')).toBeVisible()

    const emailInput = canvas.getByLabelText('Email')
    await userEvent.type(emailInput, 'test@example.com', { delay: 50 })
    await expect(emailInput).toHaveValue('test@example.com')
  },
})

import { Route, Routes, useNavigate } from 'react-router-dom'

import preview from '#.storybook/preview'
import { expect, waitFor } from 'storybook/test'

import { RestaurantDetailPage } from './RestaurantDetailPage'

const meta = preview.meta({
  component: RestaurantDetailPage,
  tags: ['ai-generated'],
  parameters: {
    layout: 'fullscreen',
    reactRouter: {
      routing: '/restaurants/1',
    },
  },
  decorators: [
    (Story) => (
      <>
        <div id="modal" />
        <Routes>
          <Route path="/restaurants/:id" element={<Story />} />
          <Route path="*" element={<RedirectToRestaurant />} />
        </Routes>
      </>
    ),
  ],
})

function RedirectToRestaurant() {
  const navigate = useNavigate()
  navigate('/restaurants/1', { replace: true })
  return null
}

export const Default = meta.story({
  play: async ({ canvas }) => {
    await waitFor(
      () => {
        expect(canvas.getByText('Burger Palace')).toBeVisible()
      },
      { timeout: 5000 }
    )
    await expect(canvas.getByText(/Burgers, Fries, Shakes/)).toBeVisible()
  },
})

export const WithMenuSections = meta.story({
  play: async ({ canvas }) => {
    await waitFor(
      () => {
        expect(canvas.getByText('To eat')).toBeVisible()
      },
      { timeout: 5000 }
    )
    await expect(canvas.getByText('Dessert')).toBeVisible()
    await expect(canvas.getByText('To drink')).toBeVisible()
  },
})

import { MemoryRouter } from 'react-router-dom'
import { ThemeProvider } from 'styled-components'
import { Provider as StoreProvider } from 'react-redux'
import { configureStore } from '@reduxjs/toolkit'
import { initialize, mswLoader } from 'msw-storybook-addon'

import { definePreview } from '@storybook/react-vite'

import { rootReducer } from '../src/app-state/store'
import { lightTheme } from '../src/styles/theme'
import { GlobalStyle } from '../src/styles/GlobalStyle'
import { mswHandlers } from './msw-handlers'

initialize({
  onUnhandledRequest: 'bypass',
})

export default definePreview({
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
    msw: {
      handlers: mswHandlers,
    },
